import React from 'react';
import './OpportunityCard.css';

const OpportunityCardCompetition = ({ opportunity, index }) => {
  const note = opportunity['Note'] || '';
  const applicationLink = opportunity['Official Link'] || opportunity['official link'] || '';

  return (
    <div className="opportunity-card" style={{display:'block'}}>
      <div >
        <div className="card-tag">#{index + 1}</div>
        <p className="card-entity-name">{opportunity['Competition Type'] || 'Competition'}</p>
        {opportunity['Country'] && <p className="field-value">{opportunity['Country']}</p>}
        {opportunity['Team Size'] && <p className="field-value">Team size: {opportunity['Team Size']}</p>}
      </div>

      <div>
        <p className="card-program-title">{opportunity['Competition Name'] || 'Untitled Competition'}</p>
        {opportunity['Organizing Body / Host Institution'] && (
          <p className="card-entity-name">{opportunity['Organizing Body / Host Institution']}</p>
        )}

        <div className="card-body">
          <div className="card-field">
            <span className="field-label">Subject Stream</span>
            <span className="field-value">{opportunity['Subject Stream'] || 'N/A'}</span>
          </div>
          <div className="card-field">
            <span className="field-label">Subject</span>
            <span className="field-value">{opportunity['Subject'] || 'N/A'}</span>
          </div>
          <div className="card-field">
            <span className="field-label">Deadline</span>
            <span className="field-value">{opportunity['Application / Registration Deadline'] || opportunity['All Deadlines'] || 'N/A'}</span>
          </div>
          <div className="card-field">
            <span className="field-label">Cost</span>
            <span className="field-value">{opportunity['Cost'] || 'Free / N/A'}</span>
          </div>
          <div className="card-field">
            <span className="field-label">Selectivity</span>
            <span className="field-value">{opportunity['Prestige / Selectivity'] || 'N/A'}</span>
          </div>
          <div className="card-field">
            <span className="field-label">Age</span>
            <span className="field-value">{opportunity['Age'] || opportunity['Ages'] || 'Any'}</span>
          </div>
          <div className="card-field">
            <span className="field-label">Grade</span>
            <span className="field-value">{opportunity['Grade'] || 'Any'}</span>
          </div>
          <div className="card-field">
            <span className="field-label">Location</span>
            <span className="field-value">{opportunity['Country'] || 'Any'}</span>
          </div>
          <div className="card-field">
            <span className="field-label">Registration</span>
            <span className="field-value">{opportunity['Deadline Passed / Not'] || 'Unknown'}</span>
          </div>
        </div>

        {note && (
          <div style={{ marginTop: '20px' }}>
            <p className="field-label">Note</p>
            <p className="field-value" style={{ whiteSpace: 'pre-wrap' }}>{note}</p>
          </div>
        )}

        {(applicationLink || opportunity['Official Rules']) && (
          <div style={{ marginTop: '20px', display: 'flex', flexWrap: 'wrap', gap: '10px' }}>
            {applicationLink && (
              <a href={applicationLink} target="_blank" rel="noreferrer" className="mui-button">
                Visit Official Link
              </a>
            )}
            {opportunity['Official Rules'] && (
              <a href={opportunity['Official Rules']} target="_blank" rel="noreferrer" className="mui-button">
                Official Rules
              </a>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

export default OpportunityCardCompetition;
